$env_node_path=$env:NODE_PATH
$new_node_path="D:\RENAL\CODE\plugy-labs\node_modules\.pnpm\@antfu+ni@25.0.0\node_modules\@antfu\ni\bin\node_modules;D:\RENAL\CODE\plugy-labs\node_modules\.pnpm\@antfu+ni@25.0.0\node_modules\@antfu\ni\node_modules;D:\RENAL\CODE\plugy-labs\node_modules\.pnpm\@antfu+ni@25.0.0\node_modules\@antfu\node_modules;D:\RENAL\CODE\plugy-labs\node_modules\.pnpm\@antfu+ni@25.0.0\node_modules;D:\RENAL\CODE\plugy-labs\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/d/RENAL/CODE/plugy-labs/node_modules/.pnpm/@antfu+ni@25.0.0/node_modules/@antfu/ni/bin/node_modules:/mnt/d/RENAL/CODE/plugy-labs/node_modules/.pnpm/@antfu+ni@25.0.0/node_modules/@antfu/ni/node_modules:/mnt/d/RENAL/CODE/plugy-labs/node_modules/.pnpm/@antfu+ni@25.0.0/node_modules/@antfu/node_modules:/mnt/d/RENAL/CODE/plugy-labs/node_modules/.pnpm/@antfu+ni@25.0.0/node_modules:/mnt/d/RENAL/CODE/plugy-labs/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../@antfu/ni/bin/nci.mjs" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../@antfu/ni/bin/nci.mjs" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../@antfu/ni/bin/nci.mjs" $args
  } else {
    & "node$exe"  "$basedir/../@antfu/ni/bin/nci.mjs" $args
  }
